/// Generate embeddings asynchronously for a list of text strings.
///
/// This is the async counterpart to [`embed_texts`]. It offloads the blocking
/// ONNX inference work to a dedicated blocking thread pool via Tokio's
/// `spawn_blocking`, keeping the async executor free.
///
/// Returns one embedding vector per input text in the same order.
///
/// # Arguments
///
/// * `texts` - Vec of strings to embed (owned, sent to blocking thread)
/// * `config` - Embedding configuration specifying model, batch size, and normalization
///
/// # Errors
///
/// - `KreuzbergError::MissingDependency` if ONNX Runtime is not installed
/// - `KreuzbergError::Embedding` if the preset name is unknown, model download fails,
///   or the blocking inference task panics
///
/// # Example
///
/// ```rust,ignore
/// use kreuzberg::{embed_texts_async, EmbeddingConfig};
///
/// let embeddings = embed_texts_async(
///     vec!["Hello!".to_string()],
///     &EmbeddingConfig::default(),
/// ).await?;
/// ```
#[rustler::nif(schedule = "DirtyCpu")]
pub fn embed_texts_async(texts: Vec<String>, config: Option<String>) -> Result<Vec<Vec<f32>>, String> {
    let config_core: Option<kreuzberg::EmbeddingConfig> = config
        .map(|s| serde_json::from_str::<kreuzberg::EmbeddingConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    std::thread::Builder::new()
        .stack_size(32 * 1024 * 1024)
        .spawn(move || {
            let rt = tokio::runtime::Runtime::new().map_err(|e| e.to_string())?;
            let result = rt
                .block_on(async {
                    kreuzberg::embed_texts_async(texts, config_core.as_ref().unwrap_or(&Default::default())).await
                })
                .map_err(|e| e.to_string())?;
            Ok(result)
        })
        .map_err(|e| e.to_string())?
        .join()
        .map_err(|_| "thread panicked".to_string())?
}

/// Render a single PDF page to PNG bytes.
///
/// Returns raw PNG-encoded bytes for the specified page at the given DPI.
/// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
///
/// # Arguments
///
/// * `pdf_bytes` - Raw PDF file bytes
/// * `page_index` - Zero-based page index
/// * `dpi` - Resolution in dots per inch (default: 150)
/// * `password` - Optional password for encrypted PDFs
///
/// # Errors
///
/// Returns `KreuzbergError::Parsing` if the PDF cannot be opened, authenticated,
/// or rendered, or if `page_index` is out of range.
#[rustler::nif]
pub fn render_pdf_page_to_png(
    pdf_bytes: rustler::Binary,
    page_index: usize,
    dpi: Option<i32>,
    password: Option<String>,
) -> Result<Vec<u8>, String> {
    let result = kreuzberg::render_pdf_page_to_png(pdf_bytes.as_slice(), page_index, dpi, password.as_deref())
        .map_err(|e| e.to_string())?;
    Ok(result.to_vec())
}

