#[rustler::nif]
pub fn register_ocr_backend(
    env: rustler::Env<'_>,
    genserver_pid: rustler::LocalPid,
    plugin_name: String,
) -> rustler::Atom {
    let bridge = RustlerOcrBackendBridge::new(genserver_pid, plugin_name);
    let arc: Arc<dyn kreuzberg::plugins::OcrBackend> = Arc::new(bridge);

    let registry = kreuzberg::plugins::registry::get_ocr_backend_registry();
    match registry.write().register(arc) {
        Ok(_) => rustler::types::atom::Atom::from_str(env, "ok").unwrap(),
        Err(_) => rustler::types::atom::Atom::from_str(env, "error").unwrap(),
    }
}

#[rustler::nif]
pub fn unregister_ocr_backend(env: rustler::Env<'_>, name: String) -> rustler::Atom {
    match kreuzberg::plugins::ocr_backend::unregister_ocr_backend(&name) {
        Ok(_) => rustler::types::atom::Atom::from_str(env, "ok").unwrap(),
        Err(_) => rustler::types::atom::Atom::from_str(env, "error").unwrap(),
    }
}

#[rustler::nif]
pub fn clear_ocr_backends(env: rustler::Env<'_>) -> rustler::Atom {
    match kreuzberg::plugins::ocr_backend::clear_ocr_backends() {
        Ok(_) => rustler::types::atom::Atom::from_str(env, "ok").unwrap(),
        Err(_) => rustler::types::atom::Atom::from_str(env, "error").unwrap(),
    }
}

