#[async_trait::async_trait]
impl kreuzberg::plugins::DocumentExtractor for RustlerDocumentExtractorBridge {
    async fn extract_bytes(
        &self,
        content: &[u8],
        mime_type: &str,
        config: &kreuzberg::ExtractionConfig,
    ) -> std::result::Result<kreuzberg::InternalDocument, kreuzberg::KreuzbergError> {
        let content = content.to_owned();
        let mime_type = mime_type.to_owned();
        let config = config.to_owned();
        let reply_id = TRAIT_REPLY_COUNTER.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        let (tx, rx) = tokio::sync::oneshot::channel::<Result<String, String>>();
        TRAIT_REPLY_CHANNELS.lock().unwrap().insert(reply_id, tx);

        let pid = self.inner;

        let args_json = {
            let mut args = serde_json::Map::new();
            args.insert(
                "content".to_string(),
                serde_json::Value::String(format!("{:?}", content)),
            );
            args.insert(
                "mime_type".to_string(),
                serde_json::Value::String(mime_type.to_string()),
            );
            args.insert("config".to_string(), serde_json::Value::String(format!("{:?}", config)));
            serde_json::Value::Object(args).to_string()
        };

        let method = "extract_bytes";

        let _ = tokio::task::spawn_blocking(move || {
            let mut env = rustler::OwnedEnv::new();
            let _ = env.send_and_clear(&pid, |env| {
                (
                    rustler::types::atom::Atom::from_str(env, "trait_call").unwrap(),
                    method,
                    args_json.as_str(),
                    reply_id,
                )
                    .encode(env)
            });
        })
        .await;

        match rx.await {
            Ok(Ok(json)) => serde_json::from_str(&json)
                .map_err(|_e| kreuzberg::KreuzbergError::Other(format!("Failed to deserialize response: {}", _e))),
            Ok(Err(msg)) => Err(kreuzberg::KreuzbergError::Other(msg)),
            Err(_) => Err(kreuzberg::KreuzbergError::Other(
                "Channel closed before reply received".to_string(),
            )),
        }
    }

    fn supported_mime_types(&self) -> &[&str] {
        let __types: Vec<String> = {
            let reply_id = TRAIT_REPLY_COUNTER.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            let (tx, rx) = tokio::sync::oneshot::channel::<Result<String, String>>();
            TRAIT_REPLY_CHANNELS.lock().unwrap().insert(reply_id, tx);

            let pid = self.inner;

            let args_json = {
                let args = serde_json::Map::new();
                serde_json::Value::Object(args).to_string()
            };

            let method = "supported_mime_types";

            tokio::task::spawn_blocking(move || {
                let mut env = rustler::OwnedEnv::new();
                let _ = env.send_and_clear(&pid, |env| {
                    (
                        rustler::types::atom::Atom::from_str(env, "trait_call").unwrap(),
                        method,
                        args_json.as_str(),
                        reply_id,
                    )
                        .encode(env)
                });
            });

            match rx.blocking_recv() {
                Ok(Ok(json)) => serde_json::from_str(&json).unwrap_or_default(),
                _ => Default::default(),
            }
        };
        let __strs: Vec<&'static str> = __types
            .into_iter()
            .map(|s| -> &'static str { Box::leak(s.into_boxed_str()) })
            .collect();
        Box::leak(__strs.into_boxed_slice())
    }
}

